import { Match3, EMOJIS, WIDTH, HEIGHT } from './game';

const canvas = document.getElementById('game-canvas') as HTMLCanvasElement;
const ctx = canvas.getContext('2d')"'!;
const tileSize = Math.min(canvas.width, canvas.height) / WIDTH;

const game = new (window as any).__Match3();
// create debug hooks
(window as any).game = game;
(window as any).advanceTime = (ms:number)=> game.advanceTime(ms);
(window as any).render_game_to_text = ()=> game.renderText();
(window as any).debug_set_board = (b:any)=> game.setBoard(b);

function render(){
  ctx.clearRect(0,0,canvas.width,canvas.height);
  for(let r=0;r<HEIGHT;r++){
    for(let c=0;c<WIDTH;c++){
      const v = game.state.board[r][c];
      ctx.fillStyle = '"'#222';
      ctx.fillRect(c*tileSize, r*tileSize, tileSize-2, tileSize-2);
      ctx.fillStyle = '#fff';
      ctx.font = (tileSize*0.6)+'px serif';
      ctx.textAlign='center'; ctx.textBaseline='middle';
      ctx.fillText(v>=0?EMOJIS[v]:'', c*tileSize+tileSize/2, r*tileSize+tileSize/2);
    }
  }
}

render();

let selected: [number,number] | null = null;

function canvasPosToCell(x:number,y:number){
  const rect = canvas.getBoundingClientRect();
  const cx = x - rect.left; const cy = y - rect.top;
  const c = Math.floor(cx / tileSize); const r = Math.floor(cy / tileSize);
  return [r,c] as [number,number];
}

canvas.addEventListener('pointerdown', (e)=>{
  const [r,c] = canvasPosToCell(e.clientX,e.clientY);
  if(selected==null){ selected=[r,c]; } else {
    const [sr,sc] = selected;
    if((game as any).tryMove(sr,sc,r,c)){
      // valid
    } else {
      // revert selected
    }
    selected = null;
    render();
  }
});

(window as any).render = render;

// expose render for tests
(window as any).render_game = render;

