import { test, expect } from '@playwright/test';
import path from 'path';

const ROOT = path.resolve(__dirname, '..');
const URL = 'http://127.0.0.1:8000';

// helper: start a static server in the test runner environment before tests.
// For CI here, we will require the user to run "'`python -m http.server 8000` in the game/ folder.

test.beforeEach(async ({ page }) => {
  await page.goto(URL);
});

// 1) valid swap increases score after resolution
test('"'valid swap increases score', async ({ page }) => {
  // set a deterministic board via eval
  await page.evaluate(()=>{
    // create a board where swapping (7,0) with (7,1) creates match of 3 in row 7
    const b = [
      [0,1,2,3,4,5,0,1],
      [0,1,2,3,4,5,0,1],
      [0,1,2,3,4,5,0,1],
      [0,1,2,3,4,5,0,1],
      [0,1,2,3,4,5,0,1],
      [0,1,2,3,4,5,0,1],
      [0,1,2,3,4,5,0,1],
      [2,2,1,3,4,5,0,1]
    ];
    (window as any).debug_set_board(b);
    (window as any).render_game();
  });
  const before = await page.evaluate(()=> (window as any).render_game_to_text());
  // perform a swap that will create a 3-in-row: swap (7,0) with (7,2) via two clicks
  const rect = await page.locator('#game-canvas').boundingBox();
  const tile = rect"'!.width / 8;
  // click cell (7,0)
  await page.mouse.click(rect!.x + tile*0.5, rect!.y + tile*7.5);
  // click cell (7,2)
  await page.mouse.click(rect!.x + tile*2.5, rect!.y + tile*7.5);
  // allow resolution
  await page.evaluate(()=> (window as any).advanceTime(1000));
  const after = await page.evaluate(()=> (window as any).render_game_to_text());
  expect(after).not.toBe(before);
});

// 2) invalid swap reverts board state
test('"'invalid swap reverts board state', async ({ page }) => {
  await page.evaluate(()=>{
    const b = Array.from({length:8},()=>Array.from({length:8},()=>0));
    (window as any).debug_set_board(b);
    (window as any).render_game();
  });
  const before = await page.evaluate(()=> (window as any).render_game_to_text());
  const rect = await page.locator('#game-canvas').boundingBox();
  const tile = rect"'!.width / 8;
  // swap two identical tiles that will not create matches
  await page.mouse.click(rect!.x + tile*0.5, rect!.y + tile*0.5);
  await page.mouse.click(rect!.x + tile*1.5, rect!.y + tile*0.5);
  // advance time
  await page.evaluate(()=> (window as any).advanceTime(500));
  const after = await page.evaluate(()=> (window as any).render_game_to_text());
  expect(after).toBe(before);
});

// 3) cascade increases combo multiplier
test('"'cascade increases combo multiplier', async ({ page }) => {
  await page.evaluate(()=>{
    // design a board that causes cascade: after initial clear, new matches appear
    const b = [
      [0,0,0,1,1,1,2,2],
      [0,1,2,3,4,5,0,1],
      [0,1,2,3,4,5,0,1],
      [0,1,2,3,4,5,0,1],
      [0,1,2,3,4,5,0,1],
      [0,1,2,3,4,5,0,1],
      [0,1,2,3,4,5,0,1],
      [2,2,2,3,4,5,0,1]
    ];
    (window as any).debug_set_board(b);
    (window as any).render_game();
  });
  await page.evaluate(()=> (window as any).advanceTime(1000));
  const text = await page.evaluate(()=> (window as any).render_game_to_text());
  // expect combo > 1
  const m = text.match(/COMBO:(\\d+)/);
  expect(m).not.toBeNull();
  expect(Number(m"'![1])).toBeGreaterThan(1);
});

TS

